import React, { useEffect, useState, useMemo } from 'react';
import { DocumentService, UserService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocState, UserRole } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    CalendarRange, Filter, Search, ChevronLeft, ChevronRight, 
    Save, Loader2, Clock, AlertTriangle, CheckCircle2, User as UserIcon,
    Calendar, ArrowRight, Activity
} from 'lucide-react';

interface Props {
    user: User;
}

const AdminGantt: React.FC<Props> = ({ user }) => {
    const [documents, setDocuments] = useState<Document[]>([]);
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);
    const [updatingId, setUpdatingId] = useState<string | null>(null);

    // Filters
    const [filterProject, setFilterProject] = useState('');
    const [filterAnalyst, setFilterAnalyst] = useState('');
    const [searchTerm, setSearchTerm] = useState('');

    // Modal State for date editing
    const [editModalDoc, setEditModalDoc] = useState<Document | null>(null);
    const [newDeadline, setNewDeadline] = useState('');

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [docs, u] = await Promise.all([
                DocumentService.getAll(),
                UserService.getAll()
            ]);
            // Filter out virtual documents (if any were passed) or only show real documents
            setDocuments(docs.filter(d => !d.id.startsWith('virtual-')));
            setUsers(u);
        } catch (e) {
            console.error("Error loading Gantt data", e);
        } finally {
            setLoading(false);
        }
    };

    const handleUpdateDeadline = async () => {
        if (!editModalDoc || !newDeadline) return;
        setUpdatingId(editModalDoc.id);
        try {
            await DocumentService.updateDeadline(editModalDoc.id, new Date(newDeadline).toISOString());
            setEditModalDoc(null);
            await loadData();
        } catch (e) {
            alert("Error al actualizar la fecha");
        } finally {
            setUpdatingId(null);
        }
    };

    // --- TIMELINE CALCULATIONS ---
    const filteredDocs = useMemo(() => {
        return documents.filter(d => {
            if (filterProject && d.project !== filterProject) return false;
            if (filterAnalyst && !d.assignees?.includes(filterAnalyst)) return false;
            if (searchTerm) {
                const term = searchTerm.toLowerCase();
                return d.title.toLowerCase().includes(term) || d.microprocess?.toLowerCase().includes(term);
            }
            return true;
        });
    }, [documents, filterProject, filterAnalyst, searchTerm]);

    const projects = useMemo(() => Array.from(new Set(documents.map(d => d.project).filter(Boolean))).sort(), [documents]);

    const getStatusInfo = (doc: Document) => {
        const now = new Date();
        const created = new Date(doc.createdAt);
        const deadline = doc.expectedEndDate ? new Date(doc.expectedEndDate) : null;

        if (!deadline) return { status: 'NO_PLAN', color: 'bg-slate-200', label: 'Sin Fecha Objetivo' };

        if (doc.state === DocState.APPROVED) return { status: 'DONE', color: 'bg-green-500', label: 'Completado' };

        if (now > deadline) return { status: 'OVERDUE', color: 'bg-red-500', label: 'Atrasado' };

        // Risky if 80% time used but not in final stages
        const totalDuration = deadline.getTime() - created.getTime();
        const elapsed = now.getTime() - created.getTime();
        const ratio = elapsed / totalDuration;

        if (ratio > 0.8 && doc.progress < 80) return { status: 'RISK', color: 'bg-orange-500', label: 'Riesgo Alto' };

        return { status: 'ON_TRACK', color: 'bg-indigo-500', label: 'En Plazo' };
    };

    if (loading) return (
        <div className="flex flex-col items-center justify-center min-h-[400px]">
            <Loader2 className="animate-spin text-indigo-600 mb-2" size={32} />
            <p className="text-slate-500 font-medium">Cargando cronogramas institucionales...</p>
        </div>
    );

    return (
        <div className="space-y-6 pb-20">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                        <CalendarRange className="text-indigo-600" />
                        Gantt de Gestión (Admin)
                    </h1>
                    <p className="text-slate-500">Planificación y control de fechas límite de informes.</p>
                </div>
            </div>

            {/* FILTERS BAR */}
            <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-wrap gap-4 items-center">
