                                    <td colSpan={4} className="py-20 text-center text-slate-400 italic">No se encontraron informes para los filtros seleccionados.</td>
                                </tr>
                            ) : filteredDocs.map(doc => {
                                const statusInfo = getStatusInfo(doc);
                                return (
                                    <tr key={doc.id} className="hover:bg-slate-50/50 transition-colors group">
                                        <td className="px-6 py-4">
                                            <div className="flex flex-col">
                                                <span className="text-[10px] font-black text-indigo-600 mb-0.5">{doc.project} - {doc.docType}</span>
                                                <span className="text-sm font-bold text-slate-800 line-clamp-1">{doc.microprocess || doc.title}</span>
                                                <div className="flex items-center gap-1 mt-1 text-[10px] text-slate-500">
                                                    <UserIcon size={10} />
                                                    <span>{doc.authorName}</span>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex flex-col gap-1">
                                                <div className={`inline-flex px-2 py-0.5 rounded-full text-[9px] font-bold border w-fit ${STATE_CONFIG[doc.state].color}`}>
                                                    {STATE_CONFIG[doc.state].label.split('(')[0]}
                                                </div>
                                                <span className="text-[10px] text-slate-400 font-mono">v{doc.version}</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="space-y-2">
                                                <div className="flex justify-between items-center text-[10px] font-bold text-slate-500">
                                                    <div className="flex items-center gap-1"><Clock size={12}/> {new Date(doc.createdAt).toLocaleDateString()}</div>
                                                    <div className="flex items-center gap-1">
                                                        {doc.expectedEndDate ? (
                                                            <span className={statusInfo.status === 'OVERDUE' ? 'text-red-500' : 'text-slate-700'}>
                                                                Meta: {new Date(doc.expectedEndDate).toLocaleDateString()}
                                                            </span>
                                                        ) : (
                                                            <span className="text-slate-400 italic">Fecha no definida</span>
                                                        )}
                                                    </div>
                                                </div>
                                                <div className="relative h-4 bg-slate-100 rounded-full border border-slate-200 overflow-hidden shadow-inner">
                                                    {/* Real Progress Bar */}
                                                    <div 
                                                        className={`absolute top-0 left-0 h-full transition-all duration-700 ${statusInfo.color} shadow-lg`}
                                                        style={{ width: `${doc.progress}%` }}
                                                    >
                                                        {doc.progress > 10 && (
                                                            <span className="flex items-center justify-center h-full text-[9px] text-white font-black">
                                                                {doc.progress}%
                                                            </span>
                                                        )}
                                                    </div>
                                                </div>
                                                {statusInfo.status === 'RISK' && (
                                                    <div className="flex items-center gap-1 text-[9px] text-orange-600 font-bold animate-pulse">
                                                        <AlertTriangle size={10} /> Proyección indica retraso potencial
                                                    </div>
                                                )}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            <button 
                                                onClick={() => {
                                                    setEditModalDoc(doc);
                                                    setNewDeadline(doc.expectedEndDate ? doc.expectedEndDate.split('T')[0] : '');
                                                }}
                                                className="p-2 bg-white border border-slate-200 rounded-lg text-slate-500 hover:text-indigo-600 hover:border-indigo-300 hover:shadow-sm transition-all"
                                                title="Gestionar Fecha Límite"
                                            >
                                                <Calendar size={18} />
                                            </button>
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* DATE EDIT MODAL */}
            {editModalDoc && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
                    <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden border border-slate-100">
                        <div className="p-5 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
                            <h3 className="text-lg font-black text-slate-800 flex items-center gap-2">
                                <Clock className="text-indigo-600" />
                                Definir Fecha Objetivo
                            </h3>
                            <button onClick={() => setEditModalDoc(null)} className="text-slate-400 hover:text-slate-600 transition-colors">
                                <ChevronLeft className="rotate-90" />
                            </button>
                        </div>
                        <div className="p-6 space-y-4">
                            <div className="p-4 bg-indigo-50 border border-indigo-100 rounded-xl">
                                <p className="text-[10px] font-black text-indigo-800 uppercase mb-1">Informe Seleccionado</p>
                                <p className="text-sm font-bold text-slate-800">{editModalDoc.title}</p>
                                <p className="text-xs text-indigo-600 mt-1">Fecha de Creación: {new Date(editModalDoc.createdAt).toLocaleDateString()}</p>
                            </div>

                            <div className="space-y-2">
                                <label className="block text-xs font-black text-slate-500 uppercase tracking-wider">Nueva Fecha de Término Esperada</label>
                                <input 
                                    type="date" 
                                    value={newDeadline}
                                    min={editModalDoc.createdAt.split('T')[0]}
                                    onChange={(e) => setNewDeadline(e.target.value)}
                                    className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none text-slate-800 font-bold transition-all"
                                />
                            </div>

                            <div className="flex gap-3 pt-4">
                                <button 
                                    onClick={() => setEditModalDoc(null)}
                                    className="flex-1 py-3 text-sm font-bold text-slate-500 hover:bg-slate-50 rounded-xl transition-all"
                                >
                                    Cancelar
                                </button>
                                <button 
                                    onClick={handleUpdateDeadline}
                                    disabled={!newDeadline || updatingId === editModalDoc.id}
                                    className="flex-1 bg-indigo-600 hover:bg-indigo-700 text-white py-3 rounded-xl font-black text-xs uppercase tracking-widest shadow-lg shadow-indigo-100 transition-all active:scale-95 disabled:opacity-50"
                                >
                                    {updatingId === editModalDoc.id ? 'Guardando...' : 'Asignar Plazo'}
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default AdminGantt;

import React, { useEffect, useState, useMemo } from 'react';
import { DocumentService, UserService, HierarchyService } from '../services/firebaseBackend';
import { Document, User, DocState, UserRole } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    CalendarRange, Filter, Search, ChevronLeft, ChevronRight, 
    Loader2, Clock, AlertTriangle, CheckCircle2, User as UserIcon,
    Calendar, Layers, Briefcase, Info, TrendingUp
} from 'lucide-react';

interface Props {
    user: User;
}

const DEFAULT_EXECUTIVE_DEADLINE = '2026-06-30T23:59:59Z';

const AdminGantt: React.FC<Props> = ({ user }) => {
    const [documents, setDocuments] = useState<Document[]>([]);
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);
    const [updatingId, setUpdatingId] = useState<string | null>(null);

    // Filters
    const [filterProject, setFilterProject] = useState('');
    const [searchTerm, setSearchTerm] = useState('');

    // Modal State
    const [editModalDoc, setEditModalDoc] = useState<Document | null>(null);
    const [newDeadline, setNewDeadline] = useState('');

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [docs, u] = await Promise.all([
                DocumentService.getAll(),
                UserService.getAll()
            ]);
            setDocuments(docs.filter(d => !d.id.startsWith('virtual-')));
            setUsers(u);
        } catch (e) {
            console.error("Error loading Gantt data", e);
        } finally {
            setLoading(false);
        }
    };

    const handleUpdateDeadline = async () => {
        if (!editModalDoc || !newDeadline) return;
        setUpdatingId(editModalDoc.id);
        try {
            await DocumentService.updateDeadline(editModalDoc.id, new Date(newDeadline).toISOString());
            setEditModalDoc(null);
            await loadData();
        } catch (e) {
            alert("Error al actualizar la fecha");
        } finally {
            setUpdatingId(null);
        }
    };

    const getStatusInfo = (doc: Document) => {
        const now = new Date();
        const created = new Date(doc.createdAt);
        // Usar fecha manual o la por defecto (Junio 2026)
        const deadline = doc.expectedEndDate ? new Date(doc.expectedEndDate) : new Date(DEFAULT_EXECUTIVE_DEADLINE);

        if (doc.state === DocState.APPROVED) return { status: 'DONE', color: 'bg-green-500', label: 'Completado' };
        if (now > deadline) return { status: 'OVERDUE', color: 'bg-red-500', label: 'Atrasado' };

        const totalDuration = deadline.getTime() - created.getTime();
        const elapsed = now.getTime() - created.getTime();
        const ratio = elapsed / totalDuration;

        if (ratio > 0.8 && doc.progress < 80) return { status: 'RISK', color: 'bg-orange-500', label: 'Riesgo Crítico' };
        return { status: 'ON_TRACK', color: 'bg-indigo-500', label: 'En Plazo' };
    };

    // Agrupación ejecutiva: Proyecto > Microproceso > Documentos
    const executiveData = useMemo(() => {
        const filtered = documents.filter(d => {
            if (filterProject && d.project !== filterProject) return false;
            if (searchTerm) {
                const term = searchTerm.toLowerCase();
                return d.title.toLowerCase().includes(term) || d.microprocess?.toLowerCase().includes(term);
            }
            return true;
        });

        const groups: Record<string, Record<string, Document[]>> = {};
        filtered.forEach(doc => {
            const p = doc.project || 'Sin Proyecto';
            const m = doc.microprocess || 'General';
            if (!groups[p]) groups[p] = {};
            if (!groups[p][m]) groups[p][m] = [];
            groups[p][m].push(doc);
        });

        return groups;
    }, [documents, filterProject, searchTerm]);

    if (loading) return (
        <div className="flex flex-col items-center justify-center min-h-[400px]">
            <Loader2 className="animate-spin text-indigo-600 mb-2" size={32} />
            <p className="text-slate-500 font-medium font-mono text-xs uppercase tracking-widest">Generando reporte ejecutivo...</p>
        </div>
    );

    return (
        <div className="space-y-6 pb-20 max-w-[1600px] mx-auto">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-black text-slate-900 flex items-center gap-3">
                        <div className="p-2 bg-indigo-600 rounded-lg text-white shadow-lg shadow-indigo-100">
                            <CalendarRange size={24} />
                        </div>
                        Control de Compromisos Institucionales
                    </h1>
                    <p className="text-slate-500 text-sm mt-1">Vista de seguimiento de hitos y plazos corporativos (Meta: Junio 2026).</p>
                </div>
            </div>

            {/* BARRA DE HERRAMIENTAS EJECUTIVA */}
            <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-200 flex flex-wrap gap-4 items-center justify-between">
                <div className="flex items-center gap-4 flex-1">
                    <div className="flex items-center gap-2 bg-slate-50 p-2 px-3 rounded-xl border border-slate-200">
                        <Briefcase size={16} className="text-slate-400" />
                        <select 
                            value={filterProject} 
                            onChange={(e) => setFilterProject(e.target.value)}
                            className="bg-transparent text-xs font-black text-slate-700 outline-none uppercase tracking-wider"
                        >
                            <option value="">TODOS LOS PROYECTOS</option>
                            <option value="HPC">HPC</option>
                            <option value="HSR">HSR</option>
                        </select>
                    </div>

                    <div className="relative flex-1 max-w-md">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                        <input 
                            type="text" 
                            placeholder="Filtrar por microproceso..." 
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-xs focus:ring-4 focus:ring-indigo-500/5 outline-none font-medium"
                        />
                    </div>
                </div>

                <div className="flex items-center gap-6 px-4 py-1 border-l border-slate-100 hidden lg:flex">
                    <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-indigo-500"></div><span className="text-[10px] font-bold text-slate-500 uppercase">En Plazo</span></div>
                    <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-orange-500"></div><span className="text-[10px] font-bold text-slate-500 uppercase">Riesgo</span></div>
                    <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-red-500"></div><span className="text-[10px] font-bold text-slate-500 uppercase">Atrasado</span></div>
                </div>
            </div>

            {/* TABLA EJECUTIVA */}
            <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead className="bg-slate-900 text-[10px] text-slate-400 font-black uppercase tracking-[0.15em] border-b border-slate-800">
                            <tr>
                                <th className="px-8 py-5 w-48">Proyecto</th>
                                <th className="px-8 py-5">Microproceso / Entregables</th>
                                <th className="px-8 py-5 w-48">Estado Operativo</th>
                                <th className="px-8 py-5 w-72">Cronograma vs Meta</th>
                                <th className="px-8 py-5 text-right w-24">Acciones</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {Object.keys(executiveData).length === 0 ? (
                                <tr>
                                    <td colSpan={5} className="py-24 text-center">
                                        <div className="flex flex-col items-center opacity-30">
                                            <Search size={48} className="mb-4" />
                                            <p className="text-sm font-black uppercase tracking-widest">Sin datos para mostrar</p>
                                        </div>
                                    </td>
                                </tr>
                            ) : Object.keys(executiveData).map(project => (
                                <React.Fragment key={project}>
                                    {Object.keys(executiveData[project]).map((micro, mIdx) => (
                                        <React.Fragment key={`${project}-${micro}`}>
                                            {executiveData[project][micro].map((doc, dIdx) => {
                                                const statusInfo = getStatusInfo(doc);
                                                const isLastInMicro = dIdx === executiveData[project][micro].length - 1;
                                                const isFirstInMicro = dIdx === 0;
                                                const isFirstInProject = mIdx === 0 && dIdx === 0;

                                                return (
                                                    <tr key={doc.id} className="hover:bg-slate-50/50 transition-all group">
                                                        {/* COLUMNA PROYECTO (Solo se muestra en el primer registro del microproceso para limpieza visual) */}
                                                        <td className="px-8 py-5 align-top">
                                                            {isFirstInMicro && (
                                                                <span className="inline-block px-3 py-1 bg-slate-800 text-white rounded-lg text-[10px] font-black tracking-widest shadow-sm">
                                                                    {project}
                                                                </span>
                                                            )}
                                                        </td>

                                                        {/* COLUMNA MICROPROCESO Y DOCUMENTOS ANIDADOS */}
                                                        <td className="px-8 py-5 align-top">
                                                            {isFirstInMicro && (
                                                                <div className="mb-3">
                                                                    <h4 className="text-sm font-black text-slate-800 uppercase tracking-tight">{micro}</h4>
                                                                </div>
                                                            )}
                                                            <div className="flex items-center gap-3 pl-4 border-l-2 border-slate-100 py-1">
                                                                <div className="p-1 bg-indigo-50 rounded text-indigo-600">
                                                                    <Layers size={12} />
                                                                </div>
                                                                <span className="text-[11px] font-bold text-slate-600 uppercase">{doc.docType}</span>
                                                                <span className="text-[10px] text-slate-400 font-mono italic">v{doc.version}</span>
                                                            </div>
                                                        </td>

                                                        {/* COLUMNA ESTADO ACTUAL */}
                                                        <td className="px-8 py-5 align-top">
                                                            <div className="flex flex-col gap-1.5 mt-1">
                                                                <div className={`inline-flex px-2 py-0.5 rounded-md text-[9px] font-black uppercase tracking-tighter border w-fit shadow-sm ${STATE_CONFIG[doc.state].color}`}>
                                                                    {STATE_CONFIG[doc.state].label.split('(')[0]}
                                                                </div>
                                                                <div className="flex items-center gap-2">
                                                                    <div className="w-full bg-slate-100 rounded-full h-1.5 overflow-hidden">
                                                                        <div className="bg-slate-800 h-full transition-all duration-1000" style={{ width: `${doc.progress}%` }}></div>
                                                                    </div>
                                                                    <span className="text-[10px] font-black text-slate-700">{doc.progress}%</span>
                                                                </div>
                                                            </div>
                                                        </td>

                                                        {/* COLUMNA CRONOGRAMA */}
                                                        <td className="px-8 py-5 align-top">
                                                            <div className="space-y-2 mt-1">
                                                                <div className="flex justify-between items-center text-[9px] font-black uppercase tracking-wider">
                                                                    <span className="text-slate-400">Desde: {new Date(doc.createdAt).toLocaleDateString()}</span>
                                                                    <span className={statusInfo.status === 'OVERDUE' ? 'text-red-600' : 'text-slate-800'}>
                                                                        Meta: {new Date(doc.expectedEndDate || DEFAULT_EXECUTIVE_DEADLINE).toLocaleDateString()}
                                                                    </span>
                                                                </div>
                                                                <div className="relative h-5 bg-slate-100 rounded-lg border border-slate-200 overflow-hidden shadow-inner p-0.5">
                                                                    <div 
                                                                        className={`h-full rounded-md transition-all duration-1000 ${statusInfo.color} flex items-center justify-end px-2`}
                                                                        style={{ width: `${doc.progress}%` }}
                                                                    >
                                                                        {doc.progress > 20 && (
                                                                            <TrendingUp size={10} className="text-white opacity-50" />
                                                                        )}
                                                                    </div>
                                                                </div>
                                                                {statusInfo.status === 'RISK' && (
                                                                    <div className="flex items-center gap-1.5 text-[9px] text-orange-600 font-black uppercase animate-pulse">
                                                                        <AlertTriangle size={12} /> Desviación detectada
                                                                    </div>
                                                                )}
                                                            </div>
                                                        </td>

                                                        {/* COLUMNA ACCIONES */}
                                                        <td className="px-8 py-5 align-top text-right">
                                                            <button 
                                                                onClick={() => {
                                                                    setEditModalDoc(doc);
                                                                    setNewDeadline(doc.expectedEndDate ? doc.expectedEndDate.split('T')[0] : DEFAULT_EXECUTIVE_DEADLINE.split('T')[0]);
                                                                }}
                                                                className="p-2.5 bg-white border border-slate-200 rounded-xl text-slate-400 hover:text-indigo-600 hover:border-indigo-200 hover:bg-indigo-50/30 hover:shadow-md transition-all active:scale-95"
                                                                title="Editar Fecha Meta"
                                                            >
                                                                <Calendar size={18} />
                                                            </button>
                                                        </td>
                                                    </tr>
                                                );
                                            })}
                                            {/* Espaciador entre microprocesos */}
                                            <tr><td colSpan={5} className="h-4 bg-slate-50/50"></td></tr>
                                        </React.Fragment>
                                    ))}
                                </React.Fragment>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* LEYENDA INFORMATIVA */}
            <div className="bg-indigo-50 border border-indigo-100 p-4 rounded-2xl flex items-start gap-3">
                <Info className="text-indigo-600 shrink-0" size={20} />
                <div className="text-xs text-indigo-900 leading-relaxed font-medium">
                    <p><b>Nota de Gestión:</b> Los informes sin fecha meta asignada manualmente asumen automáticamente el <b>30 de Junio de 2026</b> como plazo máximo corporativo.</p>
                    <p className="mt-1 opacity-70 italic">El indicador de cronograma evalúa la salud del documento basándose en el porcentaje de avance versus el tiempo total de vida del informe.</p>
                </div>
            </div>

            {/* MODAL DE EDICIÓN DE PLAZO */}
            {editModalDoc && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-fadeIn">
                    <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-md overflow-hidden border border-white/20">
                        <div className="p-8 border-b border-slate-100 bg-slate-50/50">
                            <div className="flex justify-between items-center mb-6">
                                <div className="p-3 bg-white rounded-2xl shadow-sm border border-slate-100">
                                    <Clock className="text-indigo-600" size={24} />
                                </div>
                                <button onClick={() => setEditModalDoc(null)} className="text-slate-400 hover:text-slate-600 transition-colors">
                                    <X size={24} />
                                </button>
                            </div>
                            <h3 className="text-xl font-black text-slate-800 tracking-tight">Establecer Meta Especial</h3>
                            <p className="text-slate-500 text-sm mt-1">Ajuste la fecha límite para este informe específico.</p>
                        </div>

