    const getStatusInfo = (doc: Document) => {
        const now = new Date();
        const created = new Date(doc.createdAt);
        // Usar fecha manual o la por defecto (Junio 2026)
        const deadline = doc.expectedEndDate ? new Date(doc.expectedEndDate) : new Date(DEFAULT_EXECUTIVE_DEADLINE);

        if (doc.state === DocState.APPROVED) return { status: 'DONE', color: 'bg-green-500', label: 'Completado' };
        if (now > deadline) return { status: 'OVERDUE', color: 'bg-red-500', label: 'Atrasado' };

        const totalDuration = deadline.getTime() - created.getTime();
        const elapsed = now.getTime() - created.getTime();
        const ratio = elapsed / totalDuration;

        if (ratio > 0.8 && doc.progress < 80) return { status: 'RISK', color: 'bg-orange-500', label: 'Riesgo Crítico' };
        return { status: 'ON_TRACK', color: 'bg-indigo-500', label: 'En Plazo' };
    };

