import React, { useEffect, useState, useMemo } from 'react';
import { DocumentService, UserService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocState, UserRole, DocType } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    CalendarRange, Filter, Search, ChevronLeft, ChevronRight, 
    Loader2, Clock, AlertTriangle, CheckCircle2, User as UserIcon,
    Calendar, Layers, Briefcase, Info, TrendingUp, Save, X, ArrowRight
} from 'lucide-react';

interface Props {
    user: User;
}

const DEFAULT_EXECUTIVE_DEADLINE = '2026-06-30T23:59:59Z';
const DOC_TYPE_ORDER: DocType[] = ['AS IS', 'FCE', 'PM', 'TO BE'];

const AdminGantt: React.FC<Props> = ({ user }) => {
    const [documents, setDocuments] = useState<Document[]>([]);
    const [loading, setLoading] = useState(true);
    const [updatingId, setUpdatingId] = useState<string | null>(null);

    // Filters
    const [filterProject, setFilterProject] = useState('');
    const [searchTerm, setSearchTerm] = useState('');

    // Modal State
    const [editModalDoc, setEditModalDoc] = useState<Document | null>(null);
    const [newDeadline, setNewDeadline] = useState('');

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [docs, fullHierarchy] = await Promise.all([
                DocumentService.getAll(),
                HierarchyService.getFullHierarchy()
            ]);

            // Mapeamos documentos reales para búsqueda rápida
            const realDocMap = new Map<string, Document>();
            docs.forEach(doc => {
                if (doc.project && (doc.microprocess || doc.title)) {
                    const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                    const docType = doc.docType || 'AS IS';
                    const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;

                    const existing = realDocMap.get(key);
                    if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                        realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                    }
                }
            });

            // Reconstruimos la lista unificada basada en la jerarquía oficial
            const unifiedList: Document[] = [];
            Object.keys(fullHierarchy).forEach(proj => {
                Object.keys(fullHierarchy[proj]).forEach(macro => {
                    Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                        fullHierarchy[proj][macro][proc].forEach(node => {
                            if (node.active === false) return;

                            // Siempre iterar en el orden específico solicitado
                            DOC_TYPE_ORDER.forEach(type => {
                                const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;

                                if (realDocMap.has(key)) {
                                    unifiedList.push({ ...realDocMap.get(key)!, project: proj, microprocess: node.name });
                                } else {
                                    // Documento virtual no iniciado
                                    unifiedList.push({
                                        id: `virtual-${key}`,
                                        title: `${node.name} - ${type}`,
                                        description: 'Pendiente de inicio',
                                        project: proj,
                                        microprocess: node.name,
                                        docType: type,
                                        state: DocState.NOT_STARTED,
                                        version: '-',
                                        progress: 0,
                                        files: [],
                                        createdAt: new Date().toISOString(),
                                        updatedAt: new Date(0).toISOString(),
                                        assignees: node.assignees || [],
                                        authorId: '',
                                        authorName: 'Sistema'
                                    } as Document);
                                }
                            });
                        });
                    });
                });
            });

            setDocuments(unifiedList);
        } catch (e) {
            console.error("Error loading Gantt data", e);
        } finally {
            setLoading(false);
        }
    };

    const handleUpdateDeadline = async () => {
        if (!editModalDoc || !newDeadline) return;

        // No permitir editar en documentos virtuales (deben iniciarse primero)
        if (editModalDoc.id.startsWith('virtual-')) {
            alert("Para asignar una fecha especial, el documento debe haber sido iniciado primero.");
            return;
        }

        setUpdatingId(editModalDoc.id);
        try {
            await DocumentService.updateDeadline(editModalDoc.id, new Date(newDeadline).toISOString());
            setEditModalDoc(null);
            await loadData();
        } catch (e) {
            alert("Error al actualizar la fecha");
        } finally {
            setUpdatingId(null);
        }
    };

    const getStatusInfo = (doc: Document) => {
        const now = new Date();
        const created = new Date(doc.createdAt);
        const deadline = doc.expectedEndDate ? new Date(doc.expectedEndDate) : new Date(DEFAULT_EXECUTIVE_DEADLINE);

        if (doc.state === DocState.APPROVED) return { status: 'DONE', color: 'bg-emerald-500', label: 'Completado' };
        if (now > deadline && doc.state !== DocState.APPROVED) return { status: 'OVERDUE', color: 'bg-rose-500', label: 'Atrasado' };

        if (doc.state === DocState.NOT_STARTED) return { status: 'PENDING', color: 'bg-slate-300', label: 'No Iniciado' };

        const totalDuration = deadline.getTime() - created.getTime();
        const elapsed = now.getTime() - created.getTime();
        const ratio = elapsed / totalDuration;

        if (ratio > 0.8 && doc.progress < 80) return { status: 'RISK', color: 'bg-amber-500', label: 'En Riesgo' };
        return { status: 'ON_TRACK', color: 'bg-indigo-500', label: 'En Plazo' };
    };

    // Estructura de agrupación para la vista de tabla
    const groupedData = useMemo(() => {
        const filtered = documents.filter(d => {
            if (filterProject && d.project !== filterProject) return false;
            if (searchTerm) {
                const term = searchTerm.toLowerCase();
                return d.microprocess?.toLowerCase().includes(term) || d.title.toLowerCase().includes(term);
            }
            return true;
        });

        const groups: Record<string, Record<string, Document[]>> = {};
        filtered.forEach(doc => {
            const p = doc.project || 'Sin Proyecto';
            const m = doc.microprocess || 'General';
            if (!groups[p]) groups[p] = {};
            if (!groups[p][m]) groups[p][m] = [];
            groups[p][m].push(doc);
        });

        return groups;
    }, [documents, filterProject, searchTerm]);

    if (loading) return (
        <div className="flex flex-col items-center justify-center min-h-[400px]">
            <Loader2 className="animate-spin text-indigo-600 mb-2" size={32} />
            <p className="text-slate-500 font-bold uppercase tracking-widest text-[10px]">Generando Reporte de Cronogramas...</p>
        </div>
    );

    return (
        <div className="space-y-6 pb-20 max-w-[1600px] mx-auto animate-fadeIn">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-black text-slate-900 flex items-center gap-3">
                        <div className="p-2 bg-slate-900 rounded-xl text-white shadow-lg shadow-slate-200">
                            <CalendarRange size={24} />
                        </div>
                        Gantt Estratégico de Control
                    </h1>
                    <p className="text-slate-500 text-sm mt-1 font-medium">Seguimiento institucional de hitos (Meta Corporativa: Junio 2026).</p>
                </div>
            </div>

            {/* FILTROS EJECUTIVOS */}
            <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-200 flex flex-wrap gap-4 items-center justify-between">
                <div className="flex items-center gap-4 flex-1">
                    <div className="flex items-center gap-2 bg-slate-50 p-2 px-3 rounded-xl border border-slate-200">
                        <Briefcase size={16} className="text-slate-400" />
                        <select 
                            value={filterProject} 
                            onChange={(e) => setFilterProject(e.target.value)}
                            className="bg-transparent text-xs font-black text-slate-700 outline-none uppercase tracking-widest"
                        >
                            <option value="">TODOS LOS PROYECTOS</option>
                            <option value="HPC">HPC</option>
                            <option value="HSR">HSR</option>
                        </select>
                    </div>

                    <div className="relative flex-1 max-w-md">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                        <input 
                            type="text" 
                            placeholder="Buscar por microproceso..." 
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-xs focus:ring-4 focus:ring-indigo-500/5 outline-none font-bold placeholder:font-medium"
                        />
                    </div>
                </div>

                <div className="flex items-center gap-6 px-6 py-1 border-l border-slate-100 hidden lg:flex">
                    <LegendItem color="bg-indigo-500" label="En Plazo" />
                    <LegendItem color="bg-rose-500" label="Atrasado" />
                    <LegendItem color="bg-amber-500" label="Riesgo" />
                    <LegendItem color="bg-slate-300" label="Pendiente" />
                </div>
            </div>

            {/* VISTA DE TABLA GANTT */}
            <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/40 border border-slate-200 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead className="bg-slate-900 text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] border-b border-slate-800">
                            <tr>
                                <th className="px-8 py-5 w-40">Proyecto</th>
                                <th className="px-8 py-5">Microproceso / Deliverables</th>
                                <th className="px-8 py-5 w-48">Estado Operativo</th>
                                <th className="px-8 py-5 w-80">Cronograma (Avance vs Meta)</th>
                                <th className="px-8 py-5 text-right w-24">Acciones</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {Object.keys(groupedData).length === 0 ? (
                                <tr>
                                    <td colSpan={5} className="py-32 text-center">
                                        <div className="flex flex-col items-center opacity-20">
                                            <Search size={48} className="mb-4" />
                                            <p className="text-sm font-black uppercase tracking-widest text-slate-900">Sin registros encontrados</p>
                                        </div>
                                    </td>
                                </tr>
                            ) : Object.keys(groupedData).map(project => (
                                <React.Fragment key={project}>
                                    {Object.keys(groupedData[project]).map((micro, mIdx) => (
                                        <React.Fragment key={`${project}-${micro}`}>
                                            {groupedData[project][micro].map((doc, dIdx) => {
                                                const statusInfo = getStatusInfo(doc);
                                                const isFirstInMicro = dIdx === 0;

                                                return (
                                                    <tr key={doc.id} className="hover:bg-slate-50/60 transition-all group">
                                                        {/* COLUMNA PROYECTO */}
                                                        <td className="px-8 py-5 align-top">
                                                            {isFirstInMicro && (
                                                                <span className="inline-block px-3 py-1 bg-slate-900 text-white rounded-lg text-[9px] font-black tracking-widest shadow-sm">
                                                                    {project}
                                                                </span>
                                                            )}
                                                        </td>

                                                        {/* COLUMNA MICROPROCESO Y DOCUMENTOS */}
                                                        <td className="px-8 py-5 align-top">
                                                            {isFirstInMicro && (
                                                                <div className="mb-4">
                                                                    <h4 className="text-sm font-black text-slate-900 uppercase tracking-tighter">{micro}</h4>
                                                                </div>
                                                            )}
                                                            <div className={`flex items-center gap-4 pl-4 border-l-2 py-1 ${doc.state === DocState.NOT_STARTED ? 'border-slate-200' : 'border-indigo-500'}`}>
                                                                <div className={`p-1.5 rounded-lg ${doc.state === DocState.NOT_STARTED ? 'bg-slate-100 text-slate-400' : 'bg-indigo-50 text-indigo-600 shadow-sm'}`}>
                                                                    <Layers size={14} />
                                                                </div>
                                                                <div className="flex flex-col">
                                                                    <span className={`text-[11px] font-black uppercase tracking-wide ${doc.state === DocState.NOT_STARTED ? 'text-slate-400' : 'text-slate-800'}`}>
                                                                        {doc.docType}
                                                                    </span>
                                                                    {doc.state !== DocState.NOT_STARTED && (
                                                                        <span className="text-[9px] text-slate-400 font-mono mt-0.5">VERSIÓN: {doc.version}</span>
                                                                    )}
                                                                </div>
                                                            </div>
                                                        </td>

                                                        {/* COLUMNA ESTADO OPERATIVO */}
                                                        <td className="px-8 py-5 align-top">
                                                            <div className="flex flex-col gap-2 mt-1">
                                                                <div className={`inline-flex px-2 py-1 rounded-md text-[9px] font-black uppercase tracking-tighter border w-fit shadow-sm ${STATE_CONFIG[doc.state].color}`}>
                                                                    {STATE_CONFIG[doc.state].label.split('(')[0]}
                                                                </div>
                                                                <div className="flex items-center gap-2">
                                                                    <div className="w-24 bg-slate-100 rounded-full h-1.5 overflow-hidden border border-slate-200">
                                                                        <div 
                                                                            className={`h-full transition-all duration-1000 ${doc.state === DocState.APPROVED ? 'bg-emerald-500' : 'bg-slate-900'}`} 
                                                                            style={{ width: `${doc.progress}%` }}
                                                                        ></div>
                                                                    </div>
                                                                    <span className="text-[10px] font-black text-slate-900">{doc.progress}%</span>
                                                                </div>
                                                            </div>
                                                        </td>

                                                        {/* COLUMNA CRONOGRAMA */}
                                                        <td className="px-8 py-5 align-top">
                                                            <div className="space-y-2 mt-1">
                                                                <div className="flex justify-between items-center text-[9px] font-bold uppercase tracking-wider">
                                                                    <span className="text-slate-400">Inicio: {new Date(doc.createdAt).toLocaleDateString()}</span>
                                                                    <span className={statusInfo.status === 'OVERDUE' ? 'text-rose-600 font-black' : 'text-slate-800'}>
                                                                        Meta: {new Date(doc.expectedEndDate || DEFAULT_EXECUTIVE_DEADLINE).toLocaleDateString()}
                                                                    </span>
                                                                </div>
                                                                <div className="relative h-6 bg-slate-100 rounded-xl border border-slate-200 overflow-hidden shadow-inner p-1">
                                                                    <div 
                                                                        className={`h-full rounded-lg transition-all duration-1000 ${statusInfo.color} flex items-center justify-end px-2 shadow-sm`}
                                                                        style={{ width: `${doc.progress > 5 ? doc.progress : 5}%` }}
                                                                    >
                                                                        {doc.progress > 15 && <TrendingUp size={12} className="text-white opacity-40" />}
                                                                    </div>
                                                                </div>
                                                                {statusInfo.status === 'RISK' && (
                                                                    <div className="flex items-center gap-1.5 text-[9px] text-amber-600 font-black uppercase animate-pulse">
                                                                        <AlertTriangle size={12} /> Desviación Crítica Detectada
                                                                    </div>
                                                                )}
                                                            </div>
                                                        </td>

                                                        {/* COLUMNA ACCIONES */}
                                                        <td className="px-8 py-5 align-top text-right">
                                                            <button 
                                                                disabled={doc.id.startsWith('virtual-')}
                                                                onClick={() => {
                                                                    setEditModalDoc(doc);
                                                                    setNewDeadline(doc.expectedEndDate ? doc.expectedEndDate.split('T')[0] : DEFAULT_EXECUTIVE_DEADLINE.split('T')[0]);
                                                                }}
                                                                className={`p-2.5 rounded-xl border transition-all active:scale-90 ${doc.id.startsWith('virtual-') ? 'bg-slate-50 text-slate-200 border-slate-100 cursor-not-allowed' : 'bg-white border-slate-200 text-slate-400 hover:text-indigo-600 hover:border-indigo-200 hover:shadow-md'}`}
                                                                title={doc.id.startsWith('virtual-') ? "Inicie el documento para gestionar plazos" : "Editar Plazo Específico"}
                                                            >
                                                                <Calendar size={18} />
                                                            </button>
                                                        </td>
                                                    </tr>
                                                );
                                            })}
                                            {/* Espaciador Estético entre Microprocesos */}
                                            <tr><td colSpan={5} className="h-6 bg-slate-50/40 border-y border-slate-100"></td></tr>
                                        </React.Fragment>
                                    ))}
                                </React.Fragment>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* NOTA DE GESTIÓN */}
            <div className="bg-slate-900 border border-slate-800 p-5 rounded-3xl flex items-start gap-4 shadow-xl">
                <div className="p-2 bg-indigo-600 rounded-xl text-white">
                    <Info size={20} />
                </div>
                <div className="text-xs text-slate-400 leading-relaxed">
                    <p className="text-white font-black uppercase tracking-widest mb-1">Nota de Control Institucional</p>
                    <p>Los plazos de término se calculan automáticamente hacia el <b>30 de Junio de 2026</b> a menos que se defina una meta especial. El indicador de salud del cronograma evalúa el avance porcentual contra el tiempo de vida proyectado del informe.</p>
                </div>
            </div>

            {/* MODAL EJECUTIVO DE EDICIÓN */}
            {editModalDoc && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-md animate-fadeIn">
                    <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-md overflow-hidden border border-white/20">
                        <div className="p-8 border-b border-slate-100 bg-slate-50/50">
                            <div className="flex justify-between items-center mb-6">
                                <div className="p-3 bg-white rounded-2xl shadow-sm border border-slate-100">
                                    <Clock className="text-indigo-600" size={24} />
                                </div>
                                <button onClick={() => setEditModalDoc(null)} className="text-slate-400 hover:text-slate-900 transition-colors">
                                    <X size={28} />
                                </button>
                            </div>
                            <h3 className="text-xl font-black text-slate-900 tracking-tight">Redefinir Meta de Entrega</h3>
                            <p className="text-slate-500 text-sm mt-1 font-medium">Ajuste de cronograma para informe prioritario.</p>
                        </div>

                        <div className="p-8 space-y-6">
                            <div className="p-5 bg-slate-900 rounded-3xl border border-slate-800 shadow-lg">
                                <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-2">Informe Bajo Análisis</p>
                                <p className="text-sm font-black text-white leading-tight uppercase">{editModalDoc.title}</p>
                                <div className="flex items-center gap-2 mt-3 text-[10px] text-slate-400 font-bold uppercase">
                                    <Clock size={12} /> Fecha Inicio: {new Date(editModalDoc.createdAt).toLocaleDateString()}
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2">Nueva Fecha de Término</label>
                                <input 
                                    type="date" 
                                    value={newDeadline}
                                    min={editModalDoc.createdAt.split('T')[0]}
                                    onChange={(e) => setNewDeadline(e.target.value)}
                                    className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-600 outline-none text-slate-900 font-black transition-all"
                                />
                            </div>

                            <div className="flex gap-3 pt-4">
                                <button 
                                    onClick={() => setEditModalDoc(null)}
                                    className="flex-1 py-4 text-xs font-black uppercase tracking-widest text-slate-400 hover:bg-slate-50 rounded-2xl transition-all"
                                >
                                    Cancelar
                                </button>
                                <button 
                                    onClick={handleUpdateDeadline}
                                    disabled={!newDeadline || updatingId === editModalDoc.id}
                                    className="flex-[2] bg-indigo-600 hover:bg-indigo-700 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl shadow-indigo-200 transition-all active:scale-95 disabled:opacity-50 flex items-center justify-center gap-2"
                                >
                                    {updatingId === editModalDoc.id ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />}
                                    Fijar Plazo
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

const LegendItem = ({ color, label }: { color: string, label: string }) => (
    <div className="flex items-center gap-2.5">
        <div className={`w-3 h-3 rounded-full ${color} shadow-sm`}></div>
        <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{label}</span>
    </div>
);

export default AdminGantt;

import React, { useEffect, useState, useMemo } from 'react';
import { DocumentService, UserService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocState, UserRole, DocType } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    CalendarRange, Filter, Search, ChevronLeft, ChevronRight, 
    Loader2, Clock, AlertTriangle, CheckCircle2, User as UserIcon,
    Calendar, Layers, Briefcase, Info, TrendingUp, Save, X, ArrowRight
} from 'lucide-react';

interface Props {
    user: User;
}

const DEFAULT_EXECUTIVE_DEADLINE = '2026-06-30T23:59:59Z';
const DOC_TYPE_ORDER: DocType[] = ['AS IS', 'FCE', 'PM', 'TO BE'];

const AdminGantt: React.FC<Props> = ({ user }) => {
    const [documents, setDocuments] = useState<Document[]>([]);
    const [loading, setLoading] = useState(true);
    const [updatingId, setUpdatingId] = useState<string | null>(null);

    // Filters
    const [filterProject, setFilterProject] = useState('');
    const [searchTerm, setSearchTerm] = useState('');

    // Modal State
    const [editModalDoc, setEditModalDoc] = useState<Document | null>(null);
    const [newDeadline, setNewDeadline] = useState('');

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [docs, fullHierarchy] = await Promise.all([
                DocumentService.getAll(),
                HierarchyService.getFullHierarchy()
            ]);

            // Mapeamos documentos reales para búsqueda rápida
            const realDocMap = new Map<string, Document>();
            docs.forEach(doc => {
                if (doc.project && (doc.microprocess || doc.title)) {
                    const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                    const docType = doc.docType || 'AS IS';
                    const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;

                    const existing = realDocMap.get(key);
                    if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                        realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                    }
                }
            });

            // Reconstruimos la lista unificada basada en la jerarquía oficial
            const unifiedList: Document[] = [];
            Object.keys(fullHierarchy).forEach(proj => {
                Object.keys(fullHierarchy[proj]).forEach(macro => {
                    Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                        fullHierarchy[proj][macro][proc].forEach(node => {
                            if (node.active === false) return;

                            // Siempre iterar en el orden específico solicitado
                            DOC_TYPE_ORDER.forEach(type => {
                                const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;

                                if (realDocMap.has(key)) {
                                    unifiedList.push({ ...realDocMap.get(key)!, project: proj, microprocess: node.name });
                                } else {
                                    // Documento virtual no iniciado
                                    unifiedList.push({
                                        id: `virtual-${key}`,
                                        title: `${node.name} - ${type}`,
                                        description: 'Pendiente de inicio',
                                        project: proj,
                                        microprocess: node.name,
                                        docType: type,
                                        state: DocState.NOT_STARTED,
                                        version: '-',
                                        progress: 0,
                                        files: [],
                                        createdAt: new Date().toISOString(),
                                        updatedAt: new Date(0).toISOString(),
                                        assignees: node.assignees || [],
                                        authorId: '',
                                        authorName: 'Sistema'
                                    } as Document);
                                }
                            });
                        });
                    });
                });
            });

            setDocuments(unifiedList);
        } catch (e) {
            console.error("Error loading Gantt data", e);
        } finally {
            setLoading(false);
        }
    };

    const handleUpdateDeadline = async () => {
        if (!editModalDoc || !newDeadline) return;

        // No permitir editar en documentos virtuales (deben iniciarse primero)
        if (editModalDoc.id.startsWith('virtual-')) {
            alert("Para asignar una fecha especial, el documento debe haber sido iniciado primero.");
            return;
        }

        setUpdatingId(editModalDoc.id);
        try {
            await DocumentService.updateDeadline(editModalDoc.id, new Date(newDeadline).toISOString());
            setEditModalDoc(null);
            await loadData();
        } catch (e) {
            alert("Error al actualizar la fecha");
        } finally {
            setUpdatingId(null);
        }
    };

    const getStatusInfo = (doc: Document) => {
        const now = new Date();
        const created = new Date(doc.createdAt);
        const deadline = doc.expectedEndDate ? new Date(doc.expectedEndDate) : new Date(DEFAULT_EXECUTIVE_DEADLINE);

        // Fix: doc.state check for APPROVED is already handled, removing redundant check to fix TS error
        if (doc.state === DocState.APPROVED) return { status: 'DONE', color: 'bg-emerald-500', label: 'Completado' };
        if (now > deadline) return { status: 'OVERDUE', color: 'bg-rose-500', label: 'Atrasado' };

        if (doc.state === DocState.NOT_STARTED) return { status: 'PENDING', color: 'bg-slate-300', label: 'No Iniciado' };

        const totalDuration = deadline.getTime() - created.getTime();
        const elapsed = now.getTime() - created.getTime();
        const ratio = elapsed / totalDuration;

        if (ratio > 0.8 && doc.progress < 80) return { status: 'RISK', color: 'bg-amber-500', label: 'En Riesgo' };
        return { status: 'ON_TRACK', color: 'bg-indigo-500', label: 'En Plazo' };
    };

    // Estructura de agrupación para la vista de tabla
    const groupedData = useMemo(() => {
        const filtered = documents.filter(d => {
            if (filterProject && d.project !== filterProject) return false;
            if (searchTerm) {
                const term = searchTerm.toLowerCase();
                return d.microprocess?.toLowerCase().includes(term) || d.title.toLowerCase().includes(term);
            }
            return true;
        });

        const groups: Record<string, Record<string, Document[]>> = {};
        filtered.forEach(doc => {
            const p = doc.project || 'Sin Proyecto';
            const m = doc.microprocess || 'General';
            if (!groups[p]) groups[p] = {};
            if (!groups[p][m]) groups[p][m] = [];
            groups[p][m].push(doc);
        });

        return groups;
    }, [documents, filterProject, searchTerm]);

    if (loading) return (
        <div className="flex flex-col items-center justify-center min-h-[400px]">
            <Loader2 className="animate-spin text-indigo-600 mb-2" size={32} />
            <p className="text-slate-500 font-bold uppercase tracking-widest text-[10px]">Generando Reporte de Cronogramas...</p>
        </div>
    );

    return (
        <div className="space-y-6 pb-20 max-w-[1600px] mx-auto animate-fadeIn">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-black text-slate-900 flex items-center gap-3">
                        <div className="p-2 bg-slate-900 rounded-xl text-white shadow-lg shadow-slate-200">
                            <CalendarRange size={24} />
                        </div>
                        Gantt Estratégico de Control
                    </h1>
                    <p className="text-slate-500 text-sm mt-1 font-medium">Seguimiento institucional de hitos (Meta Corporativa: Junio 2026).</p>
                </div>
            </div>

            {/* FILTROS EJECUTIVOS */}
            <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-200 flex flex-wrap gap-4 items-center justify-between">
                <div className="flex items-center gap-4 flex-1">
                    <div className="flex items-center gap-2 bg-slate-50 p-2 px-3 rounded-xl border border-slate-200">
                        <Briefcase size={16} className="text-slate-400" />
                        <select 
                            value={filterProject} 
                            onChange={(e) => setFilterProject(e.target.value)}
                            className="bg-transparent text-xs font-black text-slate-700 outline-none uppercase tracking-widest"
                        >
                            <option value="">TODOS LOS PROYECTOS</option>
                            <option value="HPC">HPC</option>
                            <option value="HSR">HSR</option>
                        </select>
                    </div>

                    <div className="relative flex-1 max-w-md">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                        <input 
                            type="text" 
                            placeholder="Buscar por microproceso..." 
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-xs focus:ring-4 focus:ring-indigo-500/5 outline-none font-bold placeholder:font-medium"
                        />
                    </div>
                </div>

                <div className="flex items-center gap-6 px-6 py-1 border-l border-slate-100 hidden lg:flex">
                    <LegendItem color="bg-indigo-500" label="En Plazo" />
                    <LegendItem color="bg-rose-500" label="Atrasado" />
                    <LegendItem color="bg-amber-500" label="Riesgo" />
                    <LegendItem color="bg-slate-300" label="Pendiente" />
                </div>
            </div>

            {/* VISTA DE TABLA GANTT */}
            <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/40 border border-slate-200 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead className="bg-slate-900 text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] border-b border-slate-800">
                            <tr>
                                <th className="px-8 py-5 w-40">Proyecto</th>
                                <th className="px-8 py-5">Microproceso / Deliverables</th>
                                <th className="px-8 py-5 w-48">Estado Operativo</th>
                                <th className="px-8 py-5 w-80">Cronograma (Avance vs Meta)</th>
                                <th className="px-8 py-5 text-right w-24">Acciones</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {Object.keys(groupedData).length === 0 ? (
                                <tr>
                                    <td colSpan={5} className="py-32 text-center">
                                        <div className="flex flex-col items-center opacity-20">
                                            <Search size={48} className="mb-4" />
                                            <p className="text-sm font-black uppercase tracking-widest text-slate-900">Sin registros encontrados</p>
                                        </div>
                                    </td>
                                </tr>
                            ) : Object.keys(groupedData).map(project => (
                                <React.Fragment key={project}>
                                    {Object.keys(groupedData[project]).map((micro, mIdx) => (
                                        <React.Fragment key={`${project}-${micro}`}>
                                            {groupedData[project][micro].map((doc, dIdx) => {
                                                const statusInfo = getStatusInfo(doc);
                                                const isFirstInMicro = dIdx === 0;

                                                return (
                                                    <tr key={doc.id} className="hover:bg-slate-50/60 transition-all group">
                                                        {/* COLUMNA PROYECTO */}
                                                        <td className="px-8 py-5 align-top">
                                                            {isFirstInMicro && (
                                                                <span className="inline-block px-3 py-1 bg-slate-900 text-white rounded-lg text-[9px] font-black tracking-widest shadow-sm">
                                                                    {project}
                                                                </span>
                                                            )}
                                                        </td>

                                                        {/* COLUMNA MICROPROCESO Y DOCUMENTOS */}
                                                        <td className="px-8 py-5 align-top">
                                                            {isFirstInMicro && (
                                                                <div className="mb-4">
                                                                    <h4 className="text-sm font-black text-slate-900 uppercase tracking-tighter">{micro}</h4>
                                                                </div>
                                                            )}
                                                            <div className={`flex items-center gap-4 pl-4 border-l-2 py-1 ${doc.state === DocState.NOT_STARTED ? 'border-slate-200' : 'border-indigo-500'}`}>
                                                                <div className={`p-1.5 rounded-lg ${doc.state === DocState.NOT_STARTED ? 'bg-slate-100 text-slate-400' : 'bg-indigo-50 text-indigo-600 shadow-sm'}`}>
                                                                    <Layers size={14} />
                                                                </div>
                                                                <div className="flex flex-col">
                                                                    <span className={`text-[11px] font-black uppercase tracking-wide ${doc.state === DocState.NOT_STARTED ? 'text-slate-400' : 'text-slate-800'}`}>
                                                                        {doc.docType}
                                                                    </span>
                                                                    {doc.state !== DocState.NOT_STARTED && (
                                                                        <span className="text-[9px] text-slate-400 font-mono mt-0.5">VERSIÓN: {doc.version}</span>
                                                                    )}
                                                                </div>
                                                            </div>
                                                        </td>

                                                        {/* COLUMNA ESTADO OPERATIVO */}
                                                        <td className="px-8 py-5 align-top">
                                                            <div className="flex flex-col gap-2 mt-1">
                                                                <div className={`inline-flex px-2 py-1 rounded-md text-[9px] font-black uppercase tracking-tighter border w-fit shadow-sm ${STATE_CONFIG[doc.state].color}`}>
                                                                    {STATE_CONFIG[doc.state].label.split('(')[0]}
                                                                </div>
                                                                <div className="flex items-center gap-2">
                                                                    <div className="w-24 bg-slate-100 rounded-full h-1.5 overflow-hidden border border-slate-200">
                                                                        <div 
                                                                            className={`h-full transition-all duration-1000 ${doc.state === DocState.APPROVED ? 'bg-emerald-500' : 'bg-slate-900'}`} 
                                                                            style={{ width: `${doc.progress}%` }}
                                                                        ></div>
                                                                    </div>
                                                                    <span className="text-[10px] font-black text-slate-900">{doc.progress}%</span>
                                                                </div>
                                                            </div>
                                                        </td>

                                                        {/* COLUMNA CRONOGRAMA */}
                                                        <td className="px-8 py-5 align-top">
                                                            <div className="space-y-2 mt-1">
                                                                <div className="flex justify-between items-center text-[9px] font-bold uppercase tracking-wider">
                                                                    <span className="text-slate-400">Inicio: {new Date(doc.createdAt).toLocaleDateString()}</span>
                                                                    <span className={statusInfo.status === 'OVERDUE' ? 'text-rose-600 font-black' : 'text-slate-800'}>
                                                                        Meta: {new Date(doc.expectedEndDate || DEFAULT_EXECUTIVE_DEADLINE).toLocaleDateString()}
                                                                    </span>
                                                                </div>
                                                                <div className="relative h-6 bg-slate-100 rounded-xl border border-slate-200 overflow-hidden shadow-inner p-1">
                                                                    <div 
                                                                        className={`h-full rounded-lg transition-all duration-1000 ${statusInfo.color} flex items-center justify-end px-2 shadow-sm`}
                                                                        style={{ width: `${doc.progress > 5 ? doc.progress : 5}%` }}
                                                                    >
                                                                        {doc.progress > 15 && <TrendingUp size={12} className="text-white opacity-40" />}
                                                                    </div>
                                                                </div>
                                                                {statusInfo.status === 'RISK' && (
                                                                    <div className="flex items-center gap-1.5 text-[9px] text-amber-600 font-black uppercase animate-pulse">
                                                                        <AlertTriangle size={12} /> Desviación Crítica Detectada
                                                                    </div>
                                                                )}
                                                            </div>
                                                        </td>

                                                        {/* COLUMNA ACCIONES */}
                                                        <td className="px-8 py-5 align-top text-right">
                                                            <button 
                                                                disabled={doc.id.startsWith('virtual-')}
                                                                onClick={() => {
                                                                    setEditModalDoc(doc);
                                                                    setNewDeadline(doc.expectedEndDate ? doc.expectedEndDate.split('T')[0] : DEFAULT_EXECUTIVE_DEADLINE.split('T')[0]);
                                                                }}
                                                                className={`p-2.5 rounded-xl border transition-all active:scale-90 ${doc.id.startsWith('virtual-') ? 'bg-slate-50 text-slate-200 border-slate-100 cursor-not-allowed' : 'bg-white border-slate-200 text-slate-400 hover:text-indigo-600 hover:border-indigo-200 hover:shadow-md'}`}
                                                                title={doc.id.startsWith('virtual-') ? "Inicie el documento para gestionar plazos" : "Editar Plazo Específico"}
                                                            >
                                                                <Calendar size={18} />
                                                            </button>
                                                        </td>
                                                    </tr>
                                                );
                                            })}
                                            {/* Espaciador Estético entre Microprocesos */}
                                            <tr><td colSpan={5} className="h-6 bg-slate-50/40 border-y border-slate-100"></td></tr>
                                        </React.Fragment>
                                    ))}
                                </React.Fragment>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* NOTA DE GESTIÓN */}
            <div className="bg-slate-900 border border-slate-800 p-5 rounded-3xl flex items-start gap-4 shadow-xl">
                <div className="p-2 bg-indigo-600 rounded-xl text-white">
                    <Info size={20} />
                </div>
                <div className="text-xs text-slate-400 leading-relaxed">
                    <p className="text-white font-black uppercase tracking-widest mb-1">Nota de Control Institucional</p>
                    <p>Los plazos de término se calculan automáticamente hacia el <b>30 de Junio de 2026</b> a menos que se defina una meta especial. El indicador de salud del cronograma evalúa el avance porcentual contra el tiempo de vida proyectado del informe.</p>
                </div>
            </div>

            {/* MODAL EJECUTIVO DE EDICIÓN */}
            {editModalDoc && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-md animate-fadeIn">
                    <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-md overflow-hidden border border-white/20">
                        <div className="p-8 border-b border-slate-100 bg-slate-50/50">
                            <div className="flex justify-between items-center mb-6">
                                <div className="p-3 bg-white rounded-2xl shadow-sm border border-slate-100">
                                    <Clock className="text-indigo-600" size={24} />
                                </div>
                                <button onClick={() => setEditModalDoc(null)} className="text-slate-400 hover:text-slate-900 transition-colors">
                                    <X size={28} />
                                </button>
                            </div>
                            <h3 className="text-xl font-black text-slate-900 tracking-tight">Redefinir Meta de Entrega</h3>
                            <p className="text-slate-500 text-sm mt-1 font-medium">Ajuste de cronograma para informe prioritario.</p>
                        </div>

                        <div className="p-8 space-y-6">
                            <div className="p-5 bg-slate-900 rounded-3xl border border-slate-800 shadow-lg">
                                <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-2">Informe Bajo Análisis</p>
                                <p className="text-sm font-black text-white leading-tight uppercase">{editModalDoc.title}</p>
                                <div className="flex items-center gap-2 mt-3 text-[10px] text-slate-400 font-bold uppercase">
                                    <Clock size={12} /> Fecha Inicio: {new Date(editModalDoc.createdAt).toLocaleDateString()}
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2">Nueva Fecha de Término</label>
                                <input 
                                    type="date" 
                                    value={newDeadline}
                                    min={editModalDoc.createdAt.split('T')[0]}
                                    onChange={(e) => setNewDeadline(e.target.value)}
                                    className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-600 outline-none text-slate-900 font-black transition-all"
                                />
                            </div>

                            <div className="flex gap-3 pt-4">
                                <button 
                                    onClick={() => setEditModalDoc(null)}
                                    className="flex-1 py-4 text-xs font-black uppercase tracking-widest text-slate-400 hover:bg-slate-50 rounded-2xl transition-all"
                                >
                                    Cancelar
                                </button>
                                <button 
                                    onClick={handleUpdateDeadline}
                                    disabled={!newDeadline || updatingId === editModalDoc.id}
                                    className="flex-[2] bg-indigo-600 hover:bg-indigo-700 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl shadow-indigo-200 transition-all active:scale-95 disabled:opacity-50 flex items-center justify-center gap-2"
                                >
                                    {updatingId === editModalDoc.id ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />}
                                    Fijar Plazo
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

const LegendItem = ({ color, label }: { color: string, label: string }) => (
    <div className="flex items-center gap-2.5">
        <div className={`w-3 h-3 rounded-full ${color} shadow-sm`}></div>
        <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{label}</span>
    </div>
);

export default AdminGantt;

import React, { useEffect, useState, useMemo } from 'react';
import { DocumentService, UserService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocState, UserRole, DocType } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    CalendarRange, Filter, Search, ChevronLeft, ChevronRight, 
    Loader2, Clock, AlertTriangle, CheckCircle2, User as UserIcon,
    Calendar, Layers, Briefcase, Info, TrendingUp, Save, X, ArrowRight
} from 'lucide-react';

interface Props {
    user: User;
}

const DEFAULT_EXECUTIVE_DEADLINE = '2026-06-30T23:59:59Z';
const DOC_TYPE_ORDER: DocType[] = ['AS IS', 'FCE', 'PM', 'TO BE'];

const AdminGantt: React.FC<Props> = ({ user }) => {
    const [documents, setDocuments] = useState<Document[]>([]);
    const [loading, setLoading] = useState(true);
    const [updatingId, setUpdatingId] = useState<string | null>(null);

    // Filters
    const [filterProject, setFilterProject] = useState('');
    const [searchTerm, setSearchTerm] = useState('');

    // Modal State
    const [editModalDoc, setEditModalDoc] = useState<Document | null>(null);
    const [newDeadline, setNewDeadline] = useState('');

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [docs, fullHierarchy] = await Promise.all([
                DocumentService.getAll(),
                HierarchyService.getFullHierarchy()
            ]);

            // Mapeamos documentos reales para búsqueda rápida
            const realDocMap = new Map<string, Document>();
            docs.forEach(doc => {
                if (doc.project && (doc.microprocess || doc.title)) {
                    const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                    const docType = doc.docType || 'AS IS';
                    const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;

                    const existing = realDocMap.get(key);
                    if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                        realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                    }
                }
            });

            // Reconstruimos la lista unificada basada en la jerarquía oficial
            const unifiedList: Document[] = [];
            Object.keys(fullHierarchy).forEach(proj => {
                Object.keys(fullHierarchy[proj]).forEach(macro => {
                    Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                        fullHierarchy[proj][macro][proc].forEach(node => {
                            if (node.active === false) return;

                            // Determinamos qué tipos son requeridos para este microproceso
                            const requiredTypes = node.requiredTypes?.length > 0 
                                ? node.requiredTypes 
                                : ['AS IS', 'FCE', 'PM', 'TO BE'];

                            // Iteramos en el orden solicitado pero solo si es requerido
                            DOC_TYPE_ORDER.forEach(type => {
                                if (!requiredTypes.includes(type)) return;

                                const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;

                                if (realDocMap.has(key)) {
                                    unifiedList.push({ ...realDocMap.get(key)!, project: proj, microprocess: node.name });
                                } else {
                                    // Documento virtual no iniciado (solo si es requerido)
                                    unifiedList.push({
                                        id: `virtual-${key}`,
                                        title: `${node.name} - ${type}`,
                                        description: 'Pendiente de inicio',
                                        project: proj,
                                        microprocess: node.name,
                                        docType: type,
                                        state: DocState.NOT_STARTED,
                                        version: '-',
                                        progress: 0,
                                        files: [],
                                        createdAt: new Date().toISOString(),
                                        updatedAt: new Date(0).toISOString(),
                                        assignees: node.assignees || [],
                                        authorId: '',
                                        authorName: 'Sistema'
                                    } as Document);
                                }
                            });
                        });
                    });
                });
            });

            setDocuments(unifiedList);
        } catch (e) {
            console.error("Error loading Gantt data", e);
        } finally {
            setLoading(false);
        }
    };

    const handleUpdateDeadline = async () => {
        if (!editModalDoc || !newDeadline) return;

        if (editModalDoc.id.startsWith('virtual-')) {
            alert("Inicie el documento antes de asignar un plazo especial.");
            return;
        }

        setUpdatingId(editModalDoc.id);
        try {
            await DocumentService.updateDeadline(editModalDoc.id, new Date(newDeadline).toISOString());
            setEditModalDoc(null);
            await loadData();
        } catch (e) {
            alert("Error al actualizar la fecha");
        } finally {
            setUpdatingId(null);
        }
    };

    const getStatusInfo = (doc: Document) => {
        const now = new Date();
        const created = new Date(doc.createdAt);
        const deadline = doc.expectedEndDate ? new Date(doc.expectedEndDate) : new Date(DEFAULT_EXECUTIVE_DEADLINE);

        if (doc.state === DocState.APPROVED) return { status: 'DONE', color: 'bg-emerald-500', label: 'Completado' };
        if (now > deadline && doc.state !== DocState.NOT_STARTED) return { status: 'OVERDUE', color: 'bg-rose-500', label: 'Atrasado' };
        if (doc.state === DocState.NOT_STARTED) return { status: 'PENDING', color: 'bg-slate-300', label: 'No Iniciado' };

        const totalDuration = deadline.getTime() - created.getTime();
        const elapsed = now.getTime() - created.getTime();
        const ratio = elapsed / totalDuration;

        if (ratio > 0.8 && doc.progress < 80) return { status: 'RISK', color: 'bg-amber-500', label: 'En Riesgo' };
        return { status: 'ON_TRACK', color: 'bg-indigo-500', label: 'En Plazo' };
    };

    const groupedData = useMemo(() => {
        const filtered = documents.filter(d => {
            if (filterProject && d.project !== filterProject) return false;
            if (searchTerm) {
                const term = searchTerm.toLowerCase();
                return d.microprocess?.toLowerCase().includes(term) || d.title.toLowerCase().includes(term);
            }
            return true;
        });

        const groups: Record<string, Record<string, Document[]>> = {};
        filtered.forEach(doc => {
            const p = doc.project || 'Sin Proyecto';
            const m = doc.microprocess || 'General';
            if (!groups[p]) groups[p] = {};
            if (!groups[p][m]) groups[p][m] = [];
            groups[p][m].push(doc);
        });

        return groups;
    }, [documents, filterProject, searchTerm]);

    if (loading) return (
        <div className="flex flex-col items-center justify-center min-h-[400px]">
            <Loader2 className="animate-spin text-indigo-600 mb-2" size={32} />
            <p className="text-slate-500 font-black uppercase tracking-widest text-[10px]">Generando Reporte Ejecutivo...</p>
        </div>
    );

    return (
        <div className="space-y-6 pb-20 max-w-[1600px] mx-auto animate-fadeIn">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-black text-slate-900 flex items-center gap-3">
                        <div className="p-2 bg-slate-900 rounded-xl text-white shadow-lg">
                            <CalendarRange size={24} />
                        </div>
                        Control Estratégico de Plazos
                    </h1>
                    <p className="text-slate-500 text-sm mt-1 font-medium">Seguimiento de entregables requeridos (Meta Corporativa: Junio 2026).</p>
                </div>
            </div>

            <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-200 flex flex-wrap gap-4 items-center justify-between">
                <div className="flex items-center gap-4 flex-1">
                    <div className="flex items-center gap-2 bg-slate-50 p-2 px-3 rounded-xl border border-slate-200">
                        <Briefcase size={16} className="text-slate-400" />
                        <select 
                            value={filterProject} 
                            onChange={(e) => setFilterProject(e.target.value)}
                            className="bg-transparent text-xs font-black text-slate-700 outline-none uppercase tracking-widest"
                        >
                            <option value="">TODOS LOS PROYECTOS</option>
                            <option value="HPC">HPC</option>
                            <option value="HSR">HSR</option>
                        </select>
                    </div>

                    <div className="relative flex-1 max-w-md">
                        <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                            type="text" 
                            placeholder="Buscar microproceso..." 
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-xs focus:ring-4 focus:ring-indigo-500/5 outline-none font-bold"
                        />
                    </div>
                </div>

                <div className="flex items-center gap-6 px-6 py-1 border-l border-slate-100 hidden lg:flex">
                    <LegendItem color="bg-indigo-500" label="En Plazo" />
                    <LegendItem color="bg-rose-500" label="Atrasado" />
                    <LegendItem color="bg-amber-500" label="En Riesgo" />
                    <LegendItem color="bg-slate-300" label="Pendiente" />
                </div>
            </div>

            <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/40 border border-slate-200 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead className="bg-slate-900 text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] border-b border-slate-800">
                            <tr>
                                <th className="px-8 py-5 w-40">Proyecto</th>
                                <th className="px-8 py-5">Microproceso / Entregables</th>
                                <th className="px-8 py-5 w-48">Estado Operativo</th>
                                <th className="px-8 py-5 w-80">Cronograma (Avance vs Meta)</th>
                                <th className="px-8 py-5 text-right w-24">Acciones</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {Object.keys(groupedData).length === 0 ? (
                                <tr>
                                    <td colSpan={5} className="py-32 text-center">
                                        <div className="flex flex-col items-center opacity-20">
                                            <Search size={48} className="mb-4" />
                                            <p className="text-sm font-black uppercase tracking-widest text-slate-900">Sin registros</p>
                                        </div>
                                    </td>
                                </tr>
                            ) : Object.keys(groupedData).map(project => (
                                <React.Fragment key={project}>
                                    {Object.keys(groupedData[project]).map((micro, mIdx) => (
                                        <React.Fragment key={`${project}-${micro}`}>
                                            {groupedData[project][micro].map((doc, dIdx) => {
                                                const statusInfo = getStatusInfo(doc);
                                                const isFirstInMicro = dIdx === 0;

                                                return (
                                                    <tr key={doc.id} className="hover:bg-slate-50/60 transition-all group">
                                                        <td className="px-8 py-5 align-top">
                                                            {isFirstInMicro && (
                                                                <span className="inline-block px-3 py-1 bg-slate-900 text-white rounded-lg text-[9px] font-black tracking-widest">
                                                                    {project}
                                                                </span>
                                                            )}
                                                        </td>

                                                        <td className="px-8 py-5 align-top">
                                                            {isFirstInMicro && (
                                                                <div className="mb-4">
                                                                    <h4 className="text-sm font-black text-slate-900 uppercase tracking-tighter">{micro}</h4>
                                                                </div>
                                                            )}
                                                            <div className={`flex items-center gap-4 pl-4 border-l-2 py-1 ${doc.state === DocState.NOT_STARTED ? 'border-slate-200' : 'border-indigo-500'}`}>
                                                                <div className={`p-1.5 rounded-lg ${doc.state === DocState.NOT_STARTED ? 'bg-slate-100 text-slate-400' : 'bg-indigo-50 text-indigo-600 shadow-sm'}`}>
                                                                    <Layers size={14} />
                                                                </div>
                                                                <div className="flex flex-col">
                                                                    <span className={`text-[11px] font-black uppercase tracking-wide ${doc.state === DocState.NOT_STARTED ? 'text-slate-400' : 'text-slate-800'}`}>
                                                                        {doc.docType}
                                                                    </span>
                                                                    {doc.state !== DocState.NOT_STARTED && (
                                                                        <span className="text-[9px] text-slate-400 font-mono mt-0.5">V{doc.version}</span>
                                                                    )}
                                                                </div>
                                                            </div>
                                                        </td>

                                                        <td className="px-8 py-5 align-top">
                                                            <div className="flex flex-col gap-2 mt-1">
                                                                <div className={`inline-flex px-2 py-1 rounded-md text-[9px] font-black uppercase tracking-tighter border w-fit shadow-sm ${STATE_CONFIG[doc.state].color}`}>
                                                                    {STATE_CONFIG[doc.state].label.split('(')[0]}
                                                                </div>
                                                                <div className="flex items-center gap-2">
                                                                    <div className="w-24 bg-slate-100 rounded-full h-1.5 overflow-hidden border border-slate-200">
                                                                        <div 
                                                                            className={`h-full transition-all duration-1000 ${doc.state === DocState.APPROVED ? 'bg-emerald-500' : 'bg-slate-900'}`} 
                                                                            style={{ width: `${doc.progress}%` }}
                                                                        ></div>
                                                                    </div>
                                                                    <span className="text-[10px] font-black text-slate-900">{doc.progress}%</span>
                                                                </div>
                                                            </div>
                                                        </td>

                                                        <td className="px-8 py-5 align-top">
                                                            <div className="space-y-2 mt-1">
                                                                <div className="flex justify-between items-center text-[9px] font-bold uppercase tracking-wider">
                                                                    <span className="text-slate-400">Inicio: {new Date(doc.createdAt).toLocaleDateString()}</span>
                                                                    <span className={statusInfo.status === 'OVERDUE' ? 'text-rose-600 font-black' : 'text-slate-800 font-black'}>
                                                                        Meta: {new Date(doc.expectedEndDate || DEFAULT_EXECUTIVE_DEADLINE).toLocaleDateString()}
                                                                    </span>
                                                                </div>
                                                                <div className="relative h-6 bg-slate-100 rounded-xl border border-slate-200 overflow-hidden shadow-inner p-1">
                                                                    <div 
                                                                        className={`h-full rounded-lg transition-all duration-1000 ${statusInfo.color} flex items-center justify-end px-2 shadow-sm`}
                                                                        style={{ width: `${doc.progress > 5 ? doc.progress : 5}%` }}
                                                                    >
                                                                        {doc.progress > 15 && <TrendingUp size={12} className="text-white opacity-40" />}
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        </td>

                                                        <td className="px-8 py-5 align-top text-right">
                                                            <button 
                                                                disabled={doc.id.startsWith('virtual-')}
                                                                onClick={() => {
                                                                    setEditModalDoc(doc);
                                                                    setNewDeadline(doc.expectedEndDate ? doc.expectedEndDate.split('T')[0] : DEFAULT_EXECUTIVE_DEADLINE.split('T')[0]);
                                                                }}
                                                                className={`p-2.5 rounded-xl border transition-all active:scale-90 ${doc.id.startsWith('virtual-') ? 'bg-slate-50 text-slate-200 border-slate-100 cursor-not-allowed' : 'bg-white border-slate-200 text-slate-400 hover:text-indigo-600 hover:border-indigo-200 hover:shadow-md'}`}
                                                            >
                                                                <Calendar size={18} />
                                                            </button>
                                                        </td>
                                                    </tr>
                                                );
                                            })}
                                            <tr><td colSpan={5} className="h-6 bg-slate-50/40 border-y border-slate-100"></td></tr>
                                        </React.Fragment>
                                    ))}
                                </React.Fragment>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            <div className="bg-slate-900 border border-slate-800 p-5 rounded-3xl flex items-start gap-4 shadow-xl">
                <div className="p-2 bg-indigo-600 rounded-xl text-white">
                    <Info size={20} />
                </div>
                <div className="text-xs text-slate-400 leading-relaxed">
                    <p className="text-white font-black uppercase tracking-widest mb-1">Nota de Gestión</p>
                    <p>Solo se visualizan los entregables requeridos según la matriz de procesos institucional. Los plazos meta asumen el <b>30 de Junio de 2026</b> como fecha de término corporativa global, a menos que el Administrador defina un plazo específico.</p>
                </div>
            </div>

            {editModalDoc && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-md animate-fadeIn">
                    <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-md overflow-hidden border border-white/20">
                        <div className="p-8 border-b border-slate-100 bg-slate-50/50">
                            <div className="flex justify-between items-center mb-6">
                                <div className="p-3 bg-white rounded-2xl shadow-sm border border-slate-100">
                                    <Clock className="text-indigo-600" size={24} />
                                </div>
                                <button onClick={() => setEditModalDoc(null)} className="text-slate-400 hover:text-slate-900">
                                    <X size={28} />
                                </button>
                            </div>
                            <h3 className="text-xl font-black text-slate-900 tracking-tight">Redefinir Plazo Meta</h3>
                            <p className="text-slate-500 text-sm mt-1 font-medium">Ajuste de cronograma para informe estratégico.</p>
                        </div>

                        <div className="p-8 space-y-6">
                            <div className="p-5 bg-slate-900 rounded-3xl border border-slate-800">
                                <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-2">Entregable</p>
                                <p className="text-sm font-black text-white leading-tight uppercase">{editModalDoc.title}</p>
                            </div>

                            <div className="space-y-2">
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2">Nueva Fecha de Entrega</label>
                                <input 
                                    type="date" 
                                    value={newDeadline}
                                    min={editModalDoc.createdAt.split('T')[0]}
                                    onChange={(e) => setNewDeadline(e.target.value)}
                                    className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-600 outline-none text-slate-900 font-black"
                                />
                            </div>

                            <div className="flex gap-3 pt-4">
                                <button 
                                    onClick={() => setEditModalDoc(null)}
                                    className="flex-1 py-4 text-xs font-black uppercase text-slate-400"
                                >
                                    Cancelar
                                </button>
                                <button 
                                    onClick={handleUpdateDeadline}
                                    disabled={!newDeadline || updatingId === editModalDoc.id}
                                    className="flex-[2] bg-indigo-600 hover:bg-indigo-700 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl disabled:opacity-50 flex items-center justify-center gap-2"
                                >
                                    {updatingId === editModalDoc.id ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />}
                                    Guardar Plazo
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

const LegendItem = ({ color, label }: { color: string, label: string }) => (
    <div className="flex items-center gap-2.5">
        <div className={`w-3 h-3 rounded-full ${color} shadow-sm`}></div>
        <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{label}</span>
    </div>
);

export default AdminGantt;

export enum UserRole {
  ADMIN = 'ADMIN',
  COORDINATOR = 'COORDINATOR',
  ANALYST = 'ANALYST',
}

export interface User {
  id: string;
  email: string;
  name: string;
  nickname?: string;
  role: UserRole;
  avatar: string;
  organization: string;
  password?: string;
  active?: boolean;
  canAccessReports?: boolean;
  canAccessReferents?: boolean;
  canAccessGantt?: boolean;
}

export interface Referent {
  id: string;
  name: string;
  email: string;
  specialty: string;
  organization: string;
}

export enum DocState {
  NOT_STARTED = 'NOT_STARTED',
  INITIATED = 'INITIATED',
  IN_PROCESS = 'IN_PROCESS',
  INTERNAL_REVIEW = 'INTERNAL_REVIEW',
  SENT_TO_REFERENT = 'SENT_TO_REFERENT',
  REFERENT_REVIEW = 'REFERENT_REVIEW',
  SENT_TO_CONTROL = 'SENT_TO_CONTROL',
  CONTROL_REVIEW = 'CONTROL_REVIEW',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED'
}

export type DocType = 'AS IS' | 'FCE' | 'PM' | 'TO BE';

export interface DocFile {
  id: string;
  name: string;
  size: number;
  type: string;
  url: string;
  uploadedAt: string;
}

export interface DocHistory {
  id: string;
  documentId: string;
  userId: string;
  userName: string;
  action: string;
  previousState: DocState;
  newState: DocState;
  version?: string;
  comment: string;
  timestamp: string;
}

export interface Notification {
  id: string;
  userId: string;
  documentId: string;
  type: 'ASSIGNMENT' | 'APPROVAL' | 'REJECTION' | 'COMMENT' | 'UPLOAD';
  title: string;
  message: string;
  isRead: boolean;
  timestamp: string;
  actorName: string;
}

export interface Document {
  id: string;
  title: string;
  description: string;
  project?: string;
  macroprocess?: string;
  process?: string;
  microprocess?: string;
  docType?: DocType;
  authorId: string;
  authorName: string;
  assignedTo?: string;
  assignees: string[];
  assignedByName?: string;
  state: DocState;
  version: string;
  progress: number;
  hasPendingRequest?: boolean;
  files: DocFile[];
  createdAt: string;
  updatedAt: string;
  expectedEndDate?: string;
}

export interface ProcessNode {
  name: string;
  docId: string;
  assignees: string[];
  referentIds?: string[];
  requiredTypes: DocType[];
  active?: boolean;
}

export interface FullHierarchy {
  [project: string]: {
    [macro: string]: {
      [process: string]: ProcessNode[];
    };
  };
}

export interface UserHierarchy {
  [project: string]: {
    [macro: string]: {
      [process: string]: string[];
    };
  };
}

export interface ParsedFilenameResult {
  valido: boolean;
  errores: string[];
  proyecto?: 'HPC' | 'HSR';
  microproceso?: string;
  tipo?: string;
  nomenclatura?: string;
  estado?: string;
  porcentaje?: number;
}

import React, { useState, useEffect } from 'react';
import { UserService } from '../services/firebaseBackend';
import { User, UserRole } from '../types';
import { Trash2, UserPlus, Shield, Briefcase, User as UserIcon, X, Lock, Pencil, Power, AlertCircle, CheckCircle, PieChart, UserCheck, Loader2, CalendarRange } from 'lucide-react';

const AdminUsers: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [updatingId, setUpdatingId] = useState<string | null>(null);

  // Form State
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [nickname, setNickname] = useState('');
  const [role, setRole] = useState<UserRole>(UserRole.ANALYST);
  const [organization, setOrganization] = useState('');
  const [password, setPassword] = useState('');
  const [canAccessReports, setCanAccessReports] = useState(false);
  const [canAccessReferents, setCanAccessReferents] = useState(false);
  const [canAccessGantt, setCanAccessGantt] = useState(false);

  useEffect(() => {
    loadUsers();
  }, []);

  const loadUsers = async () => {
    setLoading(true);
    const data = await UserService.getAll();
    setUsers(data);
    setLoading(false);
  };

  const handleTogglePermission = async (user: User, field: 'canAccessReports' | 'canAccessReferents' | 'canAccessGantt') => {
      setUpdatingId(`${user.id}-${field}`);
      const newValue = !user[field];
      try {
          await UserService.update(user.id, { [field]: newValue });
          // Actualización optimista local
          setUsers(prev => prev.map(u => u.id === user.id ? { ...u, [field]: newValue } : u));
      } catch (error) {
          console.error(error);
          alert('Error al actualizar permisos');
      } finally {
          setUpdatingId(null);
      }
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm('¿Estás seguro de que quieres eliminar permanentemente este usuario? Esta acción es irreversible.')) return;
    try {
        await UserService.delete(id);
        await loadUsers();
    } catch (error) {
        console.error(error);
    }
  };

  const handleToggleStatus = async (user: User) => {
      const action = user.active !== false ? 'inactivar' : 'activar';
      if (!window.confirm(`¿Está seguro que desea ${action} al usuario ${user.name}?`)) return;

      try {
          await UserService.toggleActiveStatus(user.id, user.active !== false);
          await loadUsers();
      } catch (error) {
          console.error(error);
          alert('Error al cambiar estado del usuario');
      }
  };

  const handleEdit = (user: User) => {
      setEditingUserId(user.id);
      setName(user.name);
      setEmail(user.email);
      setNickname(user.nickname || '');
      setRole(user.role);
      setOrganization(user.organization);
      setPassword(''); 
      setCanAccessReports(user.canAccessReports || false);
      setCanAccessReferents(user.canAccessReferents || false);
      setCanAccessGantt(user.canAccessGantt || false);
      setShowForm(true);
  };

  const handleCreateNew = () => {
      setEditingUserId(null);
      resetForm();
      setShowForm(true);
  };

  const handleCancel = () => {
      setShowForm(false);
      resetForm();
      setEditingUserId(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !email || !organization) return;

    let finalEmail = email;
    if (!finalEmail.includes('@')) {
        finalEmail += '@ugp-ssmso.cl';
    }

    try {
        if (editingUserId) {
            const updatePayload: Partial<User> = {
                name,
                email: finalEmail,
                nickname: nickname || undefined,
                role,
                organization,
                canAccessReports: role === UserRole.ANALYST ? canAccessReports : true,
                canAccessReferents: role === UserRole.ANALYST ? canAccessReferents : true,
                canAccessGantt: role === UserRole.ANALYST ? canAccessGantt : true
            };
            if (password) {
                updatePayload.password = password;
            }
            await UserService.update(editingUserId, updatePayload);
        } else {
            await UserService.create({
                id: `user-${Date.now()}`,
                name,
                email: finalEmail,
                nickname: nickname || undefined,
                role,
                organization,
                password: password || undefined,
                active: true,
                canAccessReports: role === UserRole.ANALYST ? canAccessReports : false,
                canAccessReferents: role === UserRole.ANALYST ? canAccessReferents : false,
                canAccessGantt: role === UserRole.ANALYST ? canAccessGantt : false
            } as User);
        }

        setShowForm(false);
        resetForm();
        setEditingUserId(null);
        await loadUsers();
    } catch (err: any) {
        alert(err.message);
    }
  };

  const resetForm = () => {
      setName('');
      setEmail('');
      setNickname('');
      setOrganization('');
      setRole(UserRole.ANALYST);
      setPassword('');
      setCanAccessReports(false);
      setCanAccessReferents(false);
      setCanAccessGantt(false);
  };

  return (
    <div className="space-y-6">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div>
                <h1 className="text-2xl font-bold text-slate-900">Gestión de Usuarios</h1>
                <p className="text-slate-500">Administra perfiles, permisos y estados de acceso.</p>
            </div>
            <button 
                onClick={showForm ? handleCancel : handleCreateNew}
                className={`inline-flex items-center px-4 py-2 text-white rounded-lg transition-colors shadow-sm ${showForm ? 'bg-slate-500 hover:bg-slate-600' : 'bg-indigo-600 hover:bg-indigo-700'}`}
            >
                {showForm ? <X size={18} className="mr-2" /> : <UserPlus size={18} className="mr-2" />}
                {showForm ? 'Cancelar' : 'Nuevo Usuario'}
            </button>
        </div>

        {showForm && (
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 animate-fadeIn">
                <h2 className="font-semibold text-slate-800 mb-4">{editingUserId ? 'Editar Usuario' : 'Registrar Nuevo Usuario'}</h2>
                <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Nombre Completo</label>
                        <input type="text" value={name} onChange={(e) => setName(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" required />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Email</label>
                        <input type="text" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" required placeholder="usuario@ugp-ssmso.cl" />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Usuario Corto / Nickname</label>
                        <input type="text" value={nickname} onChange={(e) => setNickname(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" placeholder="Ej: jsmith" />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Contraseña</label>
                        <input type="text" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" placeholder={editingUserId ? "••••••••" : "Opcional"} />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Organización / Área</label>
                        <input type="text" value={organization} onChange={(e) => setOrganization(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" required />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Rol</label>
                        <select value={role} onChange={(e) => setRole(e.target.value as UserRole)} className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500">
                            <option value={UserRole.ANALYST}>Analista</option>
                            <option value={UserRole.COORDINATOR}>Coordinador</option>
                            <option value={UserRole.ADMIN}>Administrador</option>
                        </select>
                    </div>

                    {/* SECCIÓN DE PERMISOS PARA ANALISTAS */}
                    {role === UserRole.ANALYST && (
                        <div className="md:col-span-2 bg-indigo-50 p-4 rounded-lg border border-indigo-100 mt-2">
                            <h3 className="text-xs font-bold text-indigo-900 uppercase mb-3 flex items-center gap-2">
                                <Shield size={14} /> Permisos de Analista (Control de Acceso)
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                <label className="flex items-center gap-3 p-2 bg-white rounded border border-indigo-200 cursor-pointer hover:bg-indigo-100/50 transition-colors">
                                    <input 
                                        type="checkbox" 
                                        checked={canAccessReports}
                                        onChange={(e) => setCanAccessReports(e.target.checked)}
                                        className="w-4 h-4 text-indigo-600 rounded focus:ring-indigo-500"
                                    />
                                    <div className="flex items-center gap-2">
                                        <PieChart size={16} className="text-indigo-500" />
                                        <span className="text-sm font-medium text-slate-700">Reportes</span>
                                    </div>
                                </label>
                                <label className="flex items-center gap-3 p-2 bg-white rounded border border-indigo-200 cursor-pointer hover:bg-indigo-100/50 transition-colors">
                                    <input 
                                        type="checkbox" 
                                        checked={canAccessReferents}
                                        onChange={(e) => setCanAccessReferents(e.target.checked)}
                                        className="w-4 h-4 text-indigo-600 rounded focus:ring-indigo-500"
                                    />
                                    <div className="flex items-center gap-2">
                                        <UserCheck size={16} className="text-indigo-500" />
                                        <span className="text-sm font-medium text-slate-700">Referentes</span>
                                    </div>
                                </label>
                                <label className="flex items-center gap-3 p-2 bg-white rounded border border-indigo-200 cursor-pointer hover:bg-indigo-100/50 transition-colors">
                                    <input 
                                        type="checkbox" 
                                        checked={canAccessGantt}
                                        onChange={(e) => setCanAccessGantt(e.target.checked)}
                                        className="w-4 h-4 text-indigo-600 rounded focus:ring-indigo-500"
                                    />
                                    <div className="flex items-center gap-2">
                                        <CalendarRange size={16} className="text-indigo-500" />
                                        <span className="text-sm font-medium text-slate-700">Diagrama Gantt</span>
                                    </div>
                                </label>
                            </div>
                        </div>
                    )}

                    <div className="md:col-span-2 flex justify-end mt-2">
                        <button type="submit" className="bg-indigo-600 text-white px-6 py-2 rounded-lg hover:bg-indigo-700 transition-colors">
                            {editingUserId ? 'Guardar Cambios' : 'Crear Usuario'}
                        </button>
                    </div>
                </form>
            </div>
        )}

        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="overflow-x-auto">
                <table className="w-full text-sm text-left">
                    <thead className="text-xs text-slate-500 uppercase bg-slate-50">
                        <tr>
                            <th className="px-6 py-3">Usuario</th>
                            <th className="px-6 py-3">Permisos</th>
                            <th className="px-6 py-3 text-center">Estado</th>
                            <th className="px-6 py-3">Rol</th>
                            <th className="px-6 py-3">Organización</th>
                            <th className="px-6 py-3 text-right">Acciones</th>
                        </tr>
                    </thead>
                    <tbody>
                        {users.map(u => (
                            <tr key={u.id} className={`border-b border-slate-50 hover:bg-slate-50 transition-colors ${u.active === false ? 'opacity-60 bg-slate-50/50' : ''}`}>
                                <td className="px-6 py-4 flex items-center gap-3">
                                    <img src={u.avatar} alt={u.name} className="w-8 h-8 rounded-full bg-slate-200" />
                                    <div>
                                        <p className="font-medium text-slate-900">{u.name}</p>
                                        <p className="text-xs text-slate-500">{u.email}</p>
                                    </div>
                                </td>
                                <td className="px-6 py-4">
                                    <div className="flex items-center gap-2">
                                        {/* BOTÓN REPORTE */}
                                        <button 
                                            onClick={() => handleTogglePermission(u, 'canAccessReports')}
                                            disabled={updatingId === `${u.id}-canAccessReports`}
                                            className={`p-1.5 rounded-lg transition-all flex items-center justify-center
                                                ${u.canAccessReports !== false 
                                                    ? 'bg-green-50 text-green-600 hover:bg-green-100' 
                                                    : 'bg-slate-50 text-slate-300 hover:bg-slate-100 hover:text-slate-400'}`}
                                            title={u.canAccessReports !== false ? "Deshabilitar Reportes" : "Habilitar Reportes"}
                                        >
